  /* ═══ SECURITY SECTION ═══ */
  "sec.eyebrow":         { sv: "03 / IT-säkerhet & medvetenhet", da: "03 / IT-sikkerhed & awareness" },
  "sec.title.1":         { sv: "Er största säkerhetsrisk är", da: "Jeres største sikkerhedsrisiko er" },
  "sec.title.2":         { sv: "mänsklig.",                da: "menneskelig." },
  "sec.intro.1":         { sv: "Över 90 % av lyckade cyberattacker börjar med ett phishing-mejl. Brandväggar och antivirus kan inte skydda mot en anställd som klickar på fel länk — men",
                           da: "Over 90 % af succesfulde cyberangreb starter med en phishing-e-mail. Firewalls og antivirus kan ikke beskytte mod en medarbejder, der klikker på det forkerte link — men" },
  "sec.intro.2":         { sv: "utbildning och testning kan det.", da: "træning og testning kan." },
  "sec.intro.3":         { sv: "MSET hjälper life science- och reglerade organisationer att bygga en säkerhetsmedveten kultur — med praktiska phishing-simuleringar och strukturerad Security Awareness Training som verkligen förändrar beteende.",
                           da: "MSET hjælper life science- og regulerede organisationer med at opbygge en sikkerhedsbevidst kultur — med praktiske phishing-simuleringer og struktureret Security Awareness Training, der faktisk ændrer adfærd." },
  "sec.deep-dive":       { sv: "Djupdyk: Security Awareness Training-program →", da: "Dybdegående: Security Awareness Training-program →" },

  "sec.attack-title":    { sv: "Vanligaste attackvägar — reglerade branscher", da: "Hyppigste angrebsveje — regulerede brancher" },
  "sec.attack.phishing": { sv: "Phishing-mejl",           da: "Phishing-e-mail" },
  "sec.attack.creds":    { sv: "Stöld av inloggningsuppgifter", da: "Tyveri af loginoplysninger" },
  "sec.attack.social":   { sv: "Social manipulering",     da: "Social manipulation" },
  "sec.attack.insider":  { sv: "Insiderhot",              da: "Insidertruslen" },
  "sec.attack.ransom":   { sv: "Ransomware",              da: "Ransomware" },
  "sec.attack.context":  { sv: "Reglerade sektorer inklusive pharma och medtech är bland de mest måltavlade globalt — högvärdig IP och patientdata är prioriterade mål.",
                           da: "Regulerede sektorer inklusive pharma og medtech er blandt de mest målrettede globalt — værdifuld IP og patientdata er højt prioriterede mål." },
  "sec.attack.sources":  { sv: "Källor: Verizon DBIR 2024 · IBM X-Force Threat Intelligence Index · ENISA Threat Landscape",
                           da: "Kilder: Verizon DBIR 2024 · IBM X-Force Threat Intelligence Index · ENISA Threat Landscape" },

  "sec.card1.title":     { sv: "Phishing-simulering & testning", da: "Phishing-simulering & test" },
  "sec.card1.body":      { sv: "Vi kör realistiska, kontrollerade phishing-kampanjer mot er organisation — mäter vem som klickar, vem som rapporterar och vem som är i riskzon. Resultaten styr riktad utbildning.",
                           da: "Vi kører realistiske, kontrollerede phishing-kampagner mod jeres organisation — måler hvem der klikker, hvem der rapporterer, og hvem der er mest udsatte. Resultaterne styrer målrettet træning." },
  "sec.card1.b1":        { sv: "Realistiska phishing-mallar (branschanpassade)", da: "Realistiske phishing-skabeloner (branchetilpassede)" },
  "sec.card1.b2":        { sv: "Riktade spear-phishing-scenarier per roll", da: "Målrettede spear phishing-scenarier pr. rolle" },
  "sec.card1.b3":        { sv: "SMS / vishing (röst-phishing)-simuleringar", da: "SMS / vishing (voice phishing)-simuleringer" },
  "sec.card1.b4":        { sv: "Spårning av klick & angivna lösenord", da: "Sporing af klik & indtastede adgangskoder" },
  "sec.card1.b5":        { sv: "Direkt lärotillfälle för den som klickar", da: "Øjeblikkelig læringsmulighed for den der klikker" },
  "sec.card1.b6":        { sv: "Rapportering per användare & avdelning", da: "Rapportering pr. bruger & afdeling" },
  "sec.card1.b7":        { sv: "Upprepad testning för att mäta förbättring", da: "Gentagen testning for at måle fremgang" },
  "sec.card1.sim-url":   { sv: "secur1ty-update.pharma-it-portal.com", da: "secur1ty-update.pharma-it-portal.com" },
  "sec.card1.sim-msg":   { sv: "Den här länken var del av ett kontrollerat MSET-phishing-test. Ditt klick har loggats.",
                           da: "Dette link var en del af en kontrolleret MSET-phishingtest. Dit klik er blevet logget." },
  "sec.card1.sim-done":  { sv: "✓ Simulering genomförd", da: "✓ Simulation gennemført" },

  "sec.card2.title":     { sv: "Security Awareness Training", da: "Security Awareness Training" },
  "sec.card2.body":      { sv: "Era medarbetare är er perimeter. Vårt rollbaserade SAT-program förvandlar anställda från svagaste länken till första försvarslinjen — med läroplan anpassad för life science och reglerat arbete, och bevisunderlag som revisorer faktiskt accepterar.",
                           da: "Jeres medarbejdere er jeres perimeter. Vores rollebaserede SAT-program gør medarbejdere fra svageste led til første forsvarslinje — med curriculum skræddersyet til life science og reguleret arbejde, og evidens, som revisorer faktisk accepterer." },
  "sec.card2.b1":        { sv: "Rollbaserad e-lärande (kvalitet, IT, lab, ledning)", da: "Rollebaseret e-læring (kvalitet, IT, lab, ledelse)" },
  "sec.card2.b2":        { sv: "GxP-specifika moduler — dataintegritet, CSV, Annex 11", da: "GxP-specifikke moduler — dataintegritet, CSV, Annex 11" },
  "sec.card2.b3":        { sv: "Ramverksanpassat bevis (ISO 27001, NIS2)", da: "Rammetilpasset evidens (ISO 27001, NIS2)" },
  "sec.card2.b4":        { sv: "Kvartalsrapportering & efterlevnadsspår", da: "Kvartalsrapportering & compliance-spor" },
  "sec.card2.b5":        { sv: "Årlig repetition & attesteringsprogram", da: "Årlig genopfriskning & attesteringsprogram" },
  "sec.card2.explore":   { sv: "Utforska hela programmet", da: "Udforsk hele programmet" },

  "sec.card3.title":     { sv: "Säkerhetspolicy & riskbedömning", da: "Sikkerhedspolitik & risikovurdering" },
  "sec.card3.body":      { sv: "Utveckla och underhåll IT-säkerhetspolicyer som både uppfyller regulatoriska krav och praktiska operativa behov — anpassade efter ISO 27001, NIS2 och sektorspecifika förväntningar.",
                           da: "Udvikl og vedligehold IT-sikkerhedspolitikker, der både opfylder regulatoriske krav og praktiske operationelle behov — tilpasset ISO 27001, NIS2 og sektorspecifikke forventninger." },
  "sec.card3.b1":        { sv: "Utveckling av IT-säkerhetspolicy", da: "Udvikling af IT-sikkerhedspolitik" },
  "sec.card3.b2":        { sv: "Riskbedömning & gap-analys", da: "Risikovurdering & gap-analyse" },
  "sec.card3.b3":        { sv: "NIS2 & ISO 27001-beredskap", da: "NIS2 & ISO 27001-parathed" },
  "sec.card3.b4":        { sv: "Incidenthanteringsplanering", da: "Planlægning af hændelseshåndtering" },
  "sec.card3.b5":        { sv: "Leverantörs- och tredjepartsriskgenomgång", da: "Leverandør- og tredjepartsrisikogennemgang" },

  "sec.card4.title":     { sv: "Åtkomstkontroll & identitetshantering", da: "Adgangskontrol & identitetsstyring" },
  "sec.card4.body":      { sv: "Rätt personer i rätt system — och ingen annan. Särskilt kritiskt i GxP-miljöer där åtkomst till validerade system måste dokumenteras och kontrolleras.",
                           da: "De rigtige personer i de rigtige systemer — og ingen andre. Særligt kritisk i GxP-miljøer, hvor adgang til validerede systemer skal dokumenteres og kontrolleres." },
  "sec.card4.b1":        { sv: "Rollbaserad åtkomstkontroll (RBAC)", da: "Rollebaseret adgangskontrol (RBAC)" },
