  /* ═══ STRATEGY SECTION ═══ */
  "strat.eyebrow":       { sv: "04 / IT-strategi & ledarskap", da: "04 / IT-strategi & ledelse" },
  "strat.title.1":       { sv: "Från där ni är till",     da: "Fra hvor I er til" },
  "strat.title.2":       { sv: "där ni behöver vara.",    da: "hvor I skal være." },
  "strat.intro":         { sv: "Många organisationer vet att deras IT behöver arbete — men saknar den interna resursen eller det oberoende perspektivet för att definiera hur bra ser ut. MSET är den utomstående blicken: ärlig bedömning, tydliga prioriteringar och en praktisk roadmap för att ta er dit.",
                           da: "Mange organisationer ved, at deres IT har brug for et løft — men mangler den interne ressource eller det uafhængige perspektiv til at definere, hvordan det gode ser ud. MSET leverer det udefrakommende blik: ærlig vurdering, klare prioriteter og en praktisk roadmap til at komme derhen." },
  "strat.cta":           { sv: "Boka ett introsamtal →",  da: "Book et intromøde →" },

  "strat.card1.title":   { sv: "Interim IT-chef",         da: "Interim IT-chef" },
  "strat.card1.body1":   { sv: "När ni behöver senior IT-ledning nu — under en övergång, en tillväxtfas, en omstrukturering eller helt enkelt i glappet mellan permanenta anställningar — kliver MSET in som er Interim IT-chef. Erfaren, leverantörsneutral och omedelbart effektiv.",
                           da: "Når I har brug for senior IT-ledelse nu — under en overgang, en vækstfase, en omstrukturering eller simpelthen i tomrummet mellem faste ansættelser — træder MSET ind som jeres Interim IT-chef. Erfaren, leverandørneutral og straks effektiv." },
  "strat.card1.body2":   { sv: "Tillgänglig deltid eller heltid, integrerad i ert ledningsteam och ansvarig för resultat.",
                           da: "Tilgængelig deltid eller fuldtid, integreret i jeres ledelsesteam og ansvarlig for resultater." },
  "strat.card1.b1":      { sv: "Strategisk IT-ledning under övergångar & glapp", da: "Strategisk IT-ledelse under overgange & huller" },
  "strat.card1.b2":      { sv: "Ägarskap av IT-budget & leverantörsförhandlingar", da: "Ejerskab af IT-budget & leverandørforhandlinger" },
  "strat.card1.b3":      { sv: "Rapportering på styrelsenivå & intressenthantering", da: "Rapportering på bestyrelsesniveau & interessenthåndtering" },
