  "strat.card2.title":   { sv: "Oberoende IT-bedömning", da: "Uafhængig IT-vurdering" },
  "strat.card2.body":    { sv: "En objektiv, utomstående granskning av hela ert IT-landskap — infrastruktur, säkerhetsläge, system, processer och team. Ingen leverantörsagenda. Ingen intern politik. Bara en ärlig bild av var ni står och vad som kräver uppmärksamhet.",
                           da: "En objektiv, udefrakommende gennemgang af hele jeres IT-landskab — infrastruktur, sikkerhedstilstand, systemer, processer og team. Ingen leverandøragenda. Ingen intern politik. Bare et ærligt billede af, hvor I står, og hvad der kræver opmærksomhed." },
  "strat.card2.b1":      { sv: "Inventarium & revision av nuvarande IT-tillstånd", da: "Opgørelse & revision af nuværende IT-tilstand" },
  "strat.card2.b2":      { sv: "Säkerhets- och efterlevnadsgapsanalys", da: "Sikkerheds- og compliance-gap-analyse" },
  "strat.card2.b3":      { sv: "Systemlandskapsgranskning (är det ändamålsenligt?)", da: "Systemlandskabsgennemgang (er det formålstjenligt?)" },
  "strat.card2.b4":      { sv: "Granskning av leverantörer & avtal", da: "Gennemgang af leverandører & kontrakter" },
  "strat.card2.b5":      { sv: "Riskidentifiering & prioritering", da: "Risikoidentifikation & prioritering" },
  "strat.card2.b6":      { sv: "Jämförelse mot branschstandarder", da: "Benchmarking mod branchestandarder" },
  "strat.card2.b7":      { sv: "Resultatrapport redo för ledningen", da: "Resultatrapport klar til ledelsen" },

  "strat.card3.title":   { sv: "IT-strategi & roadmap",   da: "IT-strategi & roadmap" },
  "strat.card3.body":    { sv: "Översätt era affärsmål till en konkret, prioriterad IT-strategi med en flerårig roadmap — som omfattar system, infrastruktur, säkerhet, efterlevnad och kompetenser. Byggd för att överleva mötet med verkligheten.",
                           da: "Oversæt jeres forretningsmål til en konkret, prioriteret IT-strategi med en flerårig roadmap — der dækker systemer, infrastruktur, sikkerhed, compliance og kompetencer. Bygget til at overleve mødet med virkeligheden." },
  "strat.card3.b1":      { sv: "Workshops för anpassning av affärs- & IT-mål", da: "Workshops til alignment af forretnings- & IT-mål" },
  "strat.card3.b2":      { sv: "Flerårig IT-investeringsroadmap", da: "Flerårig IT-investeringsroadmap" },
