  /* ═══ ABOUT SECTION ═══ */
  "about.eyebrow":       { sv: "Om MSET",                 da: "Om MSET" },
  "about.title.1":       { sv: "Oberoende expertis.",     da: "Uafhængig ekspertise." },
  "about.title.2":       { sv: "Verkliga resultat.",      da: "Reelle resultater." },
  "about.p1":            { sv: "MSET (Mjukvara som en tjänst) är en oberoende konsultfirma baserad i Skåne, Sverige, verksam som Kifarkis Nätsäkerhet. Vi kombinerar praktisk teknisk erfarenhet med en pragmatisk förståelse för vad som krävs för att arbeta i en reglerad bransch.",
                           da: "MSET (Mjukvara som en tjänst) er et uafhængigt konsulentfirma baseret i Skåne, Sverige, der opererer som Kifarkis Nätsäkerhet. Vi kombinerer praktisk teknisk erfaring med en pragmatisk forståelse af, hvad det kræver at arbejde i en reguleret branche." },
  "about.p2":            { sv: "Vi arbetar direkt med kvalitet-, IT- och driftsteam för att leverera lösningar som håller under regulatorisk granskning — och som tjänar de människor som använder dem varje dag.",
                           da: "Vi arbejder direkte med kvalitets-, IT- og driftsteams for at levere løsninger, der holder under regulatorisk granskning — og som tjener de mennesker, der bruger dem hver dag." },
  "about.quote":         { sv: "Teknik i life science ska möjliggöra bättre vetenskap — snabbare, säkrare och fullt efterlevnadsriktig. Det är den standard vi håller oss själva till i varje uppdrag.",
                           da: "Teknologi i life science skal muliggøre bedre videnskab — hurtigere, mere sikker og fuldt compliant. Det er den standard, vi holder os selv til i hvert engagement." },
  "about.tag.1":         { sv: "Life Science IT & AI",   da: "Life Science IT & AI" },
  "about.tag.2":         { sv: "Kifarkis Nätsäkerhet · Skåne, Sverige", da: "Kifarkis Nätsäkerhet · Skåne, Sverige" },

  "about.cred1.title":   { sv: "GxP & reglerade miljöer", da: "GxP & regulerede miljøer" },
  "about.cred1.body":    { sv: "Djup, praktisk erfarenhet av GMP-, GCP- och GLP-miljöer inom läkemedel, bioteknik och medicinteknik.",
                           da: "Dyb, praktisk erfaring med GMP-, GCP- og GLP-miljøer på tværs af pharma-, biotech- og medtech-organisationer." },
  "about.cred2.title":   { sv: "AI & ny teknik",          da: "AI & ny teknologi" },
  "about.cred2.body":    { sv: "Praktisk expertis i att driftsätta AI- och ML-verktyg i organisationer där efterlevnad är icke förhandlingsbar.",
                           da: "Praktisk ekspertise i at implementere AI- og ML-værktøjer i organisationer, hvor compliance ikke er til forhandling." },
  "about.cred3.title":   { sv: "Oberoende & leverantörsneutrala", da: "Uafhængige & leverandørneutrale" },
  "about.cred3.body":    { sv: "Vi rekommenderar det som är rätt för er situation — inte det som ger provision. Ärlig rådgivning, praktiska lösningar.",
                           da: "Vi anbefaler det, der er rigtigt for jeres situation — ikke det, der giver provision. Ærlig rådgivning, praktiske løsninger." },
  "about.cred4.title":   { sv: "Lokal närvaro, nordisk räckvidd", da: "Lokal tilstedeværelse, nordisk rækkevidde" },
  "about.cred4.body":    { sv: "Huvudkontor i södra Sverige, arbetar med kunder i hela Norden och övriga Europa.",
                           da: "Hovedkontor i det sydlige Sverige, arbejder med kunder i hele Norden og det øvrige Europa." },

  "about.work-with.title": { sv: "Vilka vi arbetar med", da: "Hvem vi arbejder med" },
  "about.work-with.body":  { sv: "Life science-IT är vårt hem — pharma, biotech, medtech, CRO/CMO, diagnostik, genterapi. Samma principer gäller där efterlevnad, audit trails och systemvalidering spelar roll.",
                             da: "Life science-IT er vores hjem — pharma, biotech, medtech, CRO/CMO, diagnostik, genterapi. De samme principper gælder, hvor compliance, audit trails og systemvalidering er vigtigt." },
  "about.best-when":     { sv: "Vi är som bäst när ni", da: "Vi er bedst, når I" },
  "about.chip.1":        { sv: "Driftsätter AI under GxP", da: "Implementerer AI under GxP" },
