  /* ═══ LAYERED PROGRAMME SECTION ═══ */
  "sat.layer.eyebrow":   { sv: "Lagerindelat program",     da: "Lagdelt program" },
  "sat.layer.title.1":   { sv: "Standard för alla företag.", da: "Standard for alle virksomheder." },
  "sat.layer.title.2":   { sv: "Specialiserat när ni behöver det.",
                           da: "Specialiseret når I har brug for det." },
  "sat.layer.intro":     { sv: "Vårt kärnprogram — phishing-simulering, rollbaserad e-lärande och revisionsberedd rapportering — fungerar för alla organisationer. För kunder i reglerade branscher lägger vi på GxP-specifika moduler som en generisk plattform inte kan erbjuda.",
                           da: "Vores kerneprogram — phishing-simulering, rollebaseret e-læring og revisionsparat rapportering — virker for alle organisationer. For kunder i regulerede brancher lægger vi GxP-specifikke moduler ovenpå, som en generisk platform ikke kan tilbyde." },
  "sat.layer.std-label": { sv: "Ingår",                    da: "Inkluderet" },
  "sat.layer.std-title": { sv: "Standardprogram",          da: "Standardprogram" },
  "sat.layer.std-body":  { sv: "Varje uppdrag inkluderar kärnan: realistisk phishing-simulering, rollbaserad e-lärande och revisionsberedd rapportering. Det fungerar för alla företag — IT, tillverkning, tjänster, konsultfirmor. Detta är vad de flesta kunder behöver.",
                           da: "Ethvert engagement inkluderer kernen: realistisk phishing-simulering, rollebaseret e-læring og revisionsparat rapportering. Det virker for alle virksomheder — IT, produktion, services, professionelle firmaer. Dette er, hvad de fleste kunder har brug for." },
  "sat.layer.opt-label": { sv: "Valfritt tillägg",         da: "Valgfrit tillæg" },
  "sat.layer.opt-title": { sv: "GxP-specifika moduler",    da: "GxP-specifikke moduler" },
  "sat.layer.opt-body":  { sv: "För pharma, biotech och medtech lägger vi på moduler som de flesta plattformar inte har: 21 CFR Part 11 i dagligt arbete, ALCOA+ dataintegritet, inloggningshygien för validerade system, samt phishing-scenarier för eQMS / LIMS / MES. Läggs till vid läroplanens design.",
                           da: "For pharma, biotech og medtech lægger vi moduler på, som de fleste platforme ikke har: 21 CFR Part 11 i daglig brug, ALCOA+ dataintegritet, login-hygiejne for validerede systemer og phishing-scenarier for eQMS / LIMS / MES. Tilføjes under curriculum-design." },

  /* ═══ FRAMEWORK-ALIGNED EVIDENCE ═══ */
  "sat.framework.title": { sv: "Ramverksanpassat bevis",   da: "Rammetilpasset evidens" },
  "sat.framework.body":  { sv: "Det kvartalsvisa bevispaketet kopplar ert program till ISO/IEC 27001, NIS2, 21 CFR Part 11 och EU Annex 11 — uttryckligen refererat, inte härlett. Detta är standard för varje uppdrag; kritiskt om ni är reglerade, fortfarande användbart om ni inte är det.",
                           da: "Den kvartalsvise evidenspakke kobler jeres program til ISO/IEC 27001, NIS2, 21 CFR Part 11 og EU Annex 11 — eksplicit refereret, ikke udledt. Dette er standard for hvert engagement; kritisk hvis I er regulerede, stadig nyttigt hvis I ikke er." },

  /* ═══ THE PROGRAMME — 5 components ═══ */
