  "sat.prog.title.2":    { sv: "Ett sammanhållet program.", da: "Ét sammenhængende program." },
  "sat.prog.intro":      { sv: "Byggt och levererat av MSET som en samlad managed service — inte en hög osammanhängande verktyg. En kontaktpunkt, en kvartalsrapport, ett revisionsberett bevispaket.",
                           da: "Bygget og leveret af MSET som én samlet managed service — ikke en bunke usammenhængende værktøjer. Ét kontaktpunkt, én kvartalsrapport, én revisionsparat evidenspakke." },

