  "sat.comp2.body":      { sv: "En modulär läroplan levererad via vår lärplattform, med innehåll och längd kalibrerat efter roll — lab, kvalitet, IT, ekonomi, ledning.",
                           da: "Et modulært curriculum leveret gennem vores læringsplatform, med indhold og længde kalibreret til rollen — lab, kvalitet, IT, økonomi, ledelse." },
  "sat.comp2.b1":        { sv: "Kvalitets- & QA-specifika moduler", da: "Kvalitets- & QA-specifikke moduler" },
  "sat.comp2.b2":        { sv: "Scenarier för lab / tillverkning", da: "Scenarier for lab / produktion" },
